/** A single row of chart data: keys are field names, values are numbers or category labels. */
export type Datum = Record<string, string | number>;

/** Inner padding between the SVG edge and the plotting area. */
export interface Margin {
  top: number;
  right: number;
  bottom: number;
  left: number;
}

/** Per-series visual config. `color` is a CSS color or token, e.g. 'var(--chart-1)'. */
export interface SeriesConfigEntry {
  label: string;
  color: string;
  /** Formatter preset name, e.g. 'currency:BRL' | 'percent' | 'compact'. */
  format?: string;
}

/** Maps a data field name to its series config. JSON-serializable (generative-UI ready). */
export type ChartConfig = Record<string, SeriesConfigEntry>;

export const DEFAULT_MARGIN: Margin = { top: 8, right: 8, bottom: 24, left: 40 };

import { format as d3Format } from 'd3-format';

const number = d3Format(',');
const compact = d3Format('.3~s');
const percent = d3Format('.1~%');

/**
 * Format a numeric value using a named preset. Presets are JSON-friendly
 * strings (no functions) so the styled layer's config stays serializable
 * for generative UI. Unknown presets fall back to the default number format.
 *
 * Supported: 'number' (default) | 'currency:<ISO>' | 'percent' | 'compact'.
 */
export function formatValue(value: number, preset = 'number'): string {
  if (preset.startsWith('currency:')) {
    const currency = preset.slice('currency:'.length) || 'USD';
    return new Intl.NumberFormat('en-US', { style: 'currency', currency }).format(value);
  }
  switch (preset) {
    case 'percent':
      return percent(value);
    case 'compact':
      return compact(value).toUpperCase();
    case 'number':
      return number(value);
    default:
      return number(value);
  }
}

import { scaleBand, scaleLinear, scalePoint } from 'd3-scale';

/** Continuous numeric scale (thin wrapper over d3-scale). */
export function linearScale(
  domain: readonly [number, number],
  range: readonly [number, number],
): (value: number) => number {
  return scaleLinear().domain([...domain]).range([...range]);
}

/** Categorical position scale; categories land at discrete points across the range. */
export function pointScale(
  categories: readonly string[],
  range: readonly [number, number],
): (value: string) => number {
  const scale = scalePoint<string>().domain([...categories]).range([...range]).padding(0);
  return (value: string) => scale(value) ?? 0;
}

/** A band scale: maps a category to its slot start, plus the slot geometry. */
export interface BandScale {
  (value: string): number;
  /** Width of each category's band (where bars are drawn). */
  bandwidth: number;
  /** Distance between adjacent band starts (bandwidth + padding). */
  step: number;
}

/** Categorical band scale for bars — each category gets a slot of `bandwidth`. */
export function bandScale(
  categories: readonly string[],
  range: readonly [number, number],
  padding = 0.2,
): BandScale {
  const scale = scaleBand<string>().domain([...categories]).range([...range]).padding(padding);
  const fn = ((value: string) => scale(value) ?? 0) as BandScale;
  fn.bandwidth = scale.bandwidth();
  fn.step = scale.step();
  return fn;
}

/** Round a raw maximum up to a readable axis bound (1-2-5 x 10^n). */
export function niceMax(rawMax: number): number {
  if (rawMax <= 0) return 1;
  const pow = Math.pow(10, Math.floor(Math.log10(rawMax)));
  const frac = rawMax / pow;
  const niceFrac = frac <= 1 ? 1 : frac <= 2 ? 2 : frac <= 5 ? 5 : 10;
  return niceFrac * pow;
}

import { area as d3Area, line as d3Line } from 'd3-shape';

export interface XYPoint {
  x: number;
  y: number;
}

/** SVG `d` for a line through the given points. Empty string if no points. */
export function linePath(points: readonly XYPoint[]): string {
  const gen = d3Line<XYPoint>()
    .x((p) => p.x)
    .y((p) => p.y);
  return gen([...points]) ?? '';
}

/** SVG `d` for an area between the points and a horizontal baseline. */
export function areaPath(points: readonly XYPoint[], baseline: number): string {
  const gen = d3Area<XYPoint>()
    .x((p) => p.x)
    .y0(baseline)
    .y1((p) => p.y);
  return gen([...points]) ?? '';
}

/** A series registered with the chart context, contributing values to the shared Y domain. */
export interface SeriesReg {
  key: string;
  /** Live accessor — reads current data so the domain stays reactive. */
  values: () => readonly number[];
}

/** Shared Y domain [0, max] across all registered series. Falls back to [0, 1]. */
export function computeYDomain(registrations: readonly SeriesReg[]): [number, number] {
  let max = 0;
  let seen = false;
  for (const reg of registrations) {
    for (const v of reg.values()) {
      seen = true;
      if (v > max) max = v;
    }
  }
  return [0, seen && max > 0 ? max : 1];
}

import { computed, Injectable, signal } from '@angular/core';
import { computeYDomain, type SeriesReg } from './domain';
import { linearScale, niceMax, pointScale } from './scales';
import { DEFAULT_MARGIN, type Datum, type Margin } from './types';

/**
 * Reactive hub shared by a chart frame and its child series/axes via DI.
 * The frame writes dimensions + data; series self-register their values so
 * the frame can compute a shared domain; scales are derived `computed`s.
 */
@Injectable()
export class ChartContext {
  readonly width = signal(0);
  readonly height = signal(0);
  readonly margin = signal<Margin>(DEFAULT_MARGIN);
  readonly data = signal<readonly Datum[]>([]);
  readonly xKey = signal<string>('');

  private readonly registry = signal<readonly SeriesReg[]>([]);

  register(reg: SeriesReg): void {
    this.registry.update((r) => [...r.filter((s) => s.key !== reg.key), reg]);
  }

  unregister(key: string): void {
    this.registry.update((r) => r.filter((s) => s.key !== key));
  }

  /** Registered series keys in registration order — used for grouped layouts. */
  readonly seriesKeys = computed(() => this.registry().map((s) => s.key));

  readonly innerWidth = computed(() =>
    Math.max(0, this.width() - this.margin().left - this.margin().right),
  );
  readonly innerHeight = computed(() =>
    Math.max(0, this.height() - this.margin().top - this.margin().bottom),
  );

  // Plot bounds in absolute SVG coordinates. Scales map into these so the
  // margins become real gutters (Y labels on the left, X labels below) instead
  // of dead space — without needing a `<g transform="translate(...)">` wrapper.
  readonly plotLeft = computed(() => this.margin().left);
  readonly plotRight = computed(() =>
    Math.max(this.margin().left, this.width() - this.margin().right),
  );
  readonly plotTop = computed(() => this.margin().top);
  readonly plotBottom = computed(() =>
    Math.max(this.margin().top, this.height() - this.margin().bottom),
  );

  readonly yDomain = computed<[number, number]>(() => {
    const [min, rawMax] = computeYDomain(this.registry());
    // Round the upper bound to a readable value so axis ticks land on
    // clean numbers (e.g. 305 -> 500 -> ticks 0/125/250/375/500).
    return [min, niceMax(rawMax)];
  });

  readonly yScale = computed(() =>
    linearScale(this.yDomain(), [this.plotBottom(), this.plotTop()]),
  );

  readonly xScale = computed(() =>
    pointScale(
      this.data().map((d) => String(d[this.xKey()])),
      [this.plotLeft(), this.plotRight()],
    ),
  );
}

import { computed, Directive, inject, input, type OnDestroy, type OnInit } from '@angular/core';
import { ChartContext } from './chart-context';
import { areaPath } from './shape';
import type { Datum } from './types';

/** Pure: project data through the scales into an area `d` string. */
export function computeAreaPath(
  data: readonly Datum[],
  xKey: string,
  yKey: string,
  xScale: (v: string) => number,
  yScale: (v: number) => number,
  baseline: number,
): string {
  if (data.length === 0) return '';
  const points = data.map((d) => ({
    x: xScale(String(d[xKey])),
    y: yScale(Number(d[yKey])),
  }));
  return areaPath(points, baseline);
}

/**
 * Renders a filled area for one series on a `<path>` inside a `[chartFrame]` SVG.
 * Self-registers its values so the frame's shared Y domain includes this series.
 *
 * @example `<svg:path [area]="'sales'" color="var(--chart-1)"></svg:path>`
 */
@Directive({
  selector: 'path[area]',
  host: {
    'data-slot': 'area',
    '[attr.d]': 'd()',
    '[attr.fill]': 'color()',
    '[attr.fill-opacity]': 'fillOpacity()',
  },
})
export class Area implements OnInit, OnDestroy {
  private readonly ctx = inject(ChartContext);

  /** Data field this area represents (the directive's input value). */
  readonly dataKey = input.required<string>({ alias: 'area' });
  readonly color = input<string>('currentColor');
  readonly fillOpacity = input<number>(0.25);

  readonly d = computed(() =>
    computeAreaPath(
      this.ctx.data(),
      this.ctx.xKey(),
      this.dataKey(),
      (v) => this.ctx.xScale()(v),
      (v) => this.ctx.yScale()(v),
      // Baseline = pixel position of value 0 (bottom of the plot band).
      this.ctx.yScale()(0),
    ),
  );

  ngOnInit(): void {
    const key = this.dataKey();
    this.ctx.register({
      key,
      values: () => this.ctx.data().map((row) => Number(row[key])),
    });
  }

  ngOnDestroy(): void {
    this.ctx.unregister(this.dataKey());
  }
}

import {
  computed,
  Directive,
  inject,
  input,
  type OnDestroy,
  type OnInit,
} from '@angular/core';
import { ChartContext } from './chart-context';
import { linePath } from './shape';
import type { Datum } from './types';

/** Pure: project data through the scales into a line `d` string. */
export function computeLinePath(
  data: readonly Datum[],
  xKey: string,
  yKey: string,
  xScale: (v: string) => number,
  yScale: (v: number) => number,
): string {
  if (data.length === 0) return '';
  return linePath(
    data.map((d) => ({ x: xScale(String(d[xKey])), y: yScale(Number(d[yKey])) })),
  );
}

/**
 * Renders a stroked line for one series on a `<path>` inside a `[chartFrame]` SVG.
 * Self-registers its values so the frame's shared Y domain includes this series.
 *
 * @example `<svg:path [line]="'sales'" color="var(--chart-1)"></svg:path>`
 */
@Directive({
  selector: 'path[line]',
  host: {
    'data-slot': 'line',
    fill: 'none',
    '[attr.d]': 'd()',
    '[attr.stroke]': 'color()',
  },
})
export class Line implements OnInit, OnDestroy {
  private readonly ctx = inject(ChartContext);

  readonly dataKey = input.required<string>({ alias: 'line' });
  readonly color = input<string>('currentColor');

  readonly d = computed(() =>
    computeLinePath(
      this.ctx.data(),
      this.ctx.xKey(),
      this.dataKey(),
      (v) => this.ctx.xScale()(v),
      (v) => this.ctx.yScale()(v),
    ),
  );

  ngOnInit(): void {
    const key = this.dataKey();
    this.ctx.register({
      key,
      values: () => this.ctx.data().map((row) => Number(row[key])),
    });
  }

  ngOnDestroy(): void {
    this.ctx.unregister(this.dataKey());
  }
}

import {
  computed,
  Directive,
  inject,
  input,
  type OnDestroy,
  type OnInit,
} from '@angular/core';
import { ChartContext } from './chart-context';
import { bandScale } from './scales';

export interface BarRect {
  x: number;
  y: number;
  width: number;
  height: number;
}

/**
 * Computes grouped bar rects for one series on a `<g>` inside a `[chartFrame]`
 * SVG. Self-registers values for the shared domain and positions its sub-bars
 * by series index so multiple series sit side-by-side within each category band.
 *
 * @example
 * ```html
 * <svg:g [bar]="'sales'" #b="bar">
 *   @for (r of b.bars(); track $index) { <svg:rect ... /> }
 * </svg:g>
 * ```
 */
@Directive({
  selector: 'g[bar]',
  host: { 'data-slot': 'bar' },
  exportAs: 'bar',
})
export class Bar implements OnInit, OnDestroy {
  private readonly ctx = inject(ChartContext);

  readonly dataKey = input.required<string>({ alias: 'bar' });

  readonly bars = computed<BarRect[]>(() => {
    const data = this.ctx.data();
    const xKey = this.ctx.xKey();
    const categories = data.map((d) => String(d[xKey]));
    const band = bandScale(categories, [this.ctx.plotLeft(), this.ctx.plotRight()], 0.2);
    const keys = this.ctx.seriesKeys();
    const count = Math.max(1, keys.length);
    const index = Math.max(0, keys.indexOf(this.dataKey()));
    const subWidth = band.bandwidth / count;
    const baseline = this.ctx.yScale()(0);
    const yScale = this.ctx.yScale();

    return data.map((d) => {
      const value = yScale(Number(d[this.dataKey()]));
      return {
        x: band(String(d[xKey])) + subWidth * index,
        y: value,
        width: Math.max(0, subWidth - 1),
        height: Math.max(0, baseline - value),
      };
    });
  });

  ngOnInit(): void {
    const key = this.dataKey();
    this.ctx.register({
      key,
      values: () => this.ctx.data().map((row) => Number(row[key])),
    });
  }

  ngOnDestroy(): void {
    this.ctx.unregister(this.dataKey());
  }
}

import {
  computed,
  Directive,
  inject,
  input,
  type OnDestroy,
  type OnInit,
} from '@angular/core';
import { ChartContext } from './chart-context';
import { linearScale } from './scales';

export interface ScatterPoint {
  cx: number;
  cy: number;
}

export interface ScatterXTick {
  x: number;
  label: string;
}

/**
 * Computes scatter points for one Y series against a numeric X field on a `<g>`
 * inside a `[chartFrame]` SVG. X uses a linear scale over the data's X extent;
 * Y uses the shared scale. Self-registers Y values for the shared domain.
 *
 * @example
 * ```html
 * <svg:g [scatter]="'score'" #s="scatter">
 *   @for (p of s.points(); track $index) { <svg:circle ... /> }
 * </svg:g>
 * ```
 */
@Directive({
  selector: 'g[scatter]',
  host: { 'data-slot': 'scatter' },
  exportAs: 'scatter',
})
export class Scatter implements OnInit, OnDestroy {
  private readonly ctx = inject(ChartContext);

  readonly dataKey = input.required<string>({ alias: 'scatter' });

  /** Linear X scale over the data's X extent, mapped into the plot width. */
  private readonly xScale = computed(() => {
    const xs = this.ctx.data().map((d) => Number(d[this.ctx.xKey()]));
    const lo = xs.length ? Math.min(...xs) : 0;
    const hi = xs.length ? Math.max(...xs) : 1;
    return linearScale(lo === hi ? [lo, lo + 1] : [lo, hi], [
      this.ctx.plotLeft(),
      this.ctx.plotRight(),
    ]);
  });

  readonly points = computed<ScatterPoint[]>(() => {
    const xKey = this.ctx.xKey();
    const xScale = this.xScale();
    const yScale = this.ctx.yScale();
    return this.ctx.data().map((d) => ({
      cx: xScale(Number(d[xKey])),
      cy: yScale(Number(d[this.dataKey()])),
    }));
  });

  /** Min / mid / max numeric labels for the X axis. */
  readonly xTicks = computed<ScatterXTick[]>(() => {
    const xs = this.ctx.data().map((d) => Number(d[this.ctx.xKey()]));
    if (xs.length === 0) return [];
    const lo = Math.min(...xs);
    const hi = Math.max(...xs);
    const xScale = this.xScale();
    const values = lo === hi ? [lo] : [lo, (lo + hi) / 2, hi];
    return values.map((v) => ({ x: xScale(v), label: String(Math.round(v)) }));
  });

  /** Y baseline for X tick labels, inside the bottom gutter. */
  readonly labelY = computed(() => this.ctx.plotBottom() + 16);

  ngOnInit(): void {
    const key = this.dataKey();
    this.ctx.register({
      key,
      values: () => this.ctx.data().map((row) => Number(row[key])),
    });
  }

  ngOnDestroy(): void {
    this.ctx.unregister(this.dataKey());
  }
}

/** Center + radius for a radial chart inside a width x height box. */
export interface PolarLayout {
  cx: number;
  cy: number;
  radius: number;
}

/** Compute the center and a radius that fits the box, minus padding for labels. */
export function polarLayout(width: number, height: number, pad = 8): PolarLayout {
  return {
    cx: width / 2,
    cy: height / 2,
    radius: Math.max(0, Math.min(width, height) / 2 - pad),
  };
}

/** Cartesian point on a circle. Angle in radians, 0 at the top, clockwise. */
export function polarPoint(
  cx: number,
  cy: number,
  radius: number,
  angle: number,
): { x: number; y: number } {
  return {
    x: cx + radius * Math.sin(angle),
    y: cy - radius * Math.cos(angle),
  };
}

/** Closed SVG polygon `d` through the given points. Empty string if < 2 points. */
export function polygonPath(points: readonly { x: number; y: number }[]): string {
  if (points.length < 2) return '';
  return `M${points.map((p) => `${p.x},${p.y}`).join('L')}Z`;
}

import { computed, Directive, inject, input } from '@angular/core';
import { arc as d3Arc, pie as d3Pie, type PieArcDatum } from 'd3-shape';
import { ChartContext } from './chart-context';
import { polarLayout } from './polar';

export interface PieSlice {
  d: string;
  index: number;
  name: string;
  value: number;
}

/**
 * Computes pie/donut slices on a `<g>` inside a `[chartFrame]` SVG. The slice
 * value is `[pie]` (a data field); the slice name is the frame's `xKey`. Set
 * `innerRadiusRatio` > 0 for a donut. Apply the directive's `transform` to the
 * `<g>` so the pie is centered.
 *
 * @example
 * ```html
 * <svg:g [pie]="'visitors'" #p="pie" [attr.transform]="p.transform()">
 *   @for (s of p.slices(); track s.name) { <svg:path [attr.d]="s.d" ... /> }
 * </svg:g>
 * ```
 */
@Directive({
  selector: 'g[pie]',
  host: { 'data-slot': 'pie' },
  exportAs: 'pie',
})
export class Pie {
  private readonly ctx = inject(ChartContext);

  readonly valueKey = input.required<string>({ alias: 'pie' });
  /** 0 = full pie; e.g. 0.6 = donut with a hole at 60% of the radius. */
  readonly innerRadiusRatio = input<number>(0);

  private readonly layout = computed(() => polarLayout(this.ctx.width(), this.ctx.height(), 8));

  /** Translate to apply to the host `<g>` so (0,0) is the pie center. */
  readonly transform = computed(() => `translate(${this.layout().cx},${this.layout().cy})`);

  readonly slices = computed<PieSlice[]>(() => {
    const data = this.ctx.data();
    const nameKey = this.ctx.xKey();
    const valueKey = this.valueKey();
    const values = data.map((d) => Number(d[valueKey]));
    const arcs = d3Pie<number>().sort(null)(values);
    const radius = this.layout().radius;
    const gen = d3Arc<PieArcDatum<number>>()
      .innerRadius(radius * this.innerRadiusRatio())
      .outerRadius(radius);
    return arcs.map((a, i) => ({
      d: gen(a) ?? '',
      index: i,
      name: String(data[i]?.[nameKey] ?? ''),
      value: values[i],
    }));
  });
}

import {
  computed,
  Directive,
  inject,
  input,
  type OnDestroy,
  type OnInit,
} from '@angular/core';
import { ChartContext } from './chart-context';
import { polarLayout, polarPoint, polygonPath } from './polar';

export interface RadarAxis {
  x2: number;
  y2: number;
  label: string;
  lx: number;
  ly: number;
}

/**
 * Computes a closed radar polygon for one series on a `<g>` inside a
 * `[chartFrame]` SVG. Categories radiate as spokes (one per data row, by the
 * frame's `xKey`); the value maps to distance along each spoke. Self-registers
 * values so all series share the same radial max. Exposes `axes()`/`rings()`
 * (the same for every series) — render them once (e.g. for the first series).
 *
 * @example `<svg:g [radar]="'desktop'" #r="radar"><svg:path [attr.d]="r.d()"/></svg:g>`
 */
@Directive({
  selector: 'g[radar]',
  host: { 'data-slot': 'radar' },
  exportAs: 'radar',
})
export class Radar implements OnInit, OnDestroy {
  private readonly ctx = inject(ChartContext);

  readonly dataKey = input.required<string>({ alias: 'radar' });
  readonly color = input<string>('currentColor');

  private readonly layout = computed(() =>
    polarLayout(this.ctx.width(), this.ctx.height(), 28),
  );

  readonly center = computed(() => this.layout());

  readonly d = computed(() => {
    const data = this.ctx.data();
    const n = data.length;
    if (n === 0) return '';
    const [, max] = this.ctx.yDomain();
    const { cx, cy, radius } = this.layout();
    const points = data.map((row, i) => {
      const angle = (i / n) * 2 * Math.PI;
      const r = (Number(row[this.dataKey()]) / max) * radius;
      return polarPoint(cx, cy, r, angle);
    });
    return polygonPath(points);
  });

  /** Spoke endpoints + category labels (shared across series). */
  readonly axes = computed<RadarAxis[]>(() => {
    const data = this.ctx.data();
    const n = data.length;
    const { cx, cy, radius } = this.layout();
    return data.map((row, i) => {
      const angle = (i / n) * 2 * Math.PI;
      const end = polarPoint(cx, cy, radius, angle);
      const label = polarPoint(cx, cy, radius + 14, angle);
      return {
        x2: end.x,
        y2: end.y,
        label: String(row[this.ctx.xKey()]),
        lx: label.x,
        ly: label.y,
      };
    });
  });

  /** Concentric reference rings (shared across series). */
  readonly rings = computed<string[]>(() => {
    const data = this.ctx.data();
    const n = data.length;
    if (n === 0) return [];
    const { cx, cy, radius } = this.layout();
    return [0.25, 0.5, 0.75, 1].map((level) =>
      polygonPath(
        data.map((_, i) =>
          polarPoint(cx, cy, radius * level, (i / n) * 2 * Math.PI),
        ),
      ),
    );
  });

  ngOnInit(): void {
    const key = this.dataKey();
    this.ctx.register({
      key,
      values: () => this.ctx.data().map((row) => Number(row[key])),
    });
  }

  ngOnDestroy(): void {
    this.ctx.unregister(this.dataKey());
  }
}

import { computed, Directive, inject, input } from '@angular/core';
import { arc as d3Arc } from 'd3-shape';
import { ChartContext } from './chart-context';
import { polarLayout } from './polar';

export interface RadialArc {
  /** Value arc (sweep proportional to the value). */
  d: string;
  /** Full-circle track behind the value arc. */
  track: string;
  index: number;
  name: string;
  value: number;
}

interface ArcInput {
  innerRadius: number;
  outerRadius: number;
  startAngle: number;
  endAngle: number;
}

/**
 * Computes concentric radial bars on a `<g>` inside a `[chartFrame]` SVG — one
 * ring per data row, sweep proportional to its `[radialBar]` value (relative to
 * the largest value). Apply the directive's `transform` to center the `<g>`.
 *
 * @example
 * ```html
 * <svg:g [radialBar]="'visitors'" #r="radialBar" [attr.transform]="r.transform()">
 *   @for (a of r.arcs(); track a.name) { <svg:path [attr.d]="a.d" ... /> }
 * </svg:g>
 * ```
 */
@Directive({
  selector: 'g[radialBar]',
  host: { 'data-slot': 'radial-bar' },
  exportAs: 'radialBar',
})
export class RadialBar {
  private readonly ctx = inject(ChartContext);

  readonly valueKey = input.required<string>({ alias: 'radialBar' });

  private readonly layout = computed(() => polarLayout(this.ctx.width(), this.ctx.height(), 8));

  readonly transform = computed(() => `translate(${this.layout().cx},${this.layout().cy})`);

  readonly arcs = computed<RadialArc[]>(() => {
    const data = this.ctx.data();
    const n = data.length;
    if (n === 0) return [];
    const valueKey = this.valueKey();
    const nameKey = this.ctx.xKey();
    const values = data.map((d) => Number(d[valueKey]));
    const max = Math.max(...values, 1);
    const { radius } = this.layout();
    const band = radius / (n + 0.5);
    const gen = d3Arc<ArcInput>().cornerRadius(band * 0.35);

    return data.map((row, i) => {
      const outer = radius - band * i;
      const inner = outer - band * 0.7;
      const endAngle = (values[i] / max) * 2 * Math.PI;
      const base = { innerRadius: inner, outerRadius: outer, startAngle: 0 };
      return {
        d: gen({ ...base, endAngle }) ?? '',
        track: gen({ ...base, endAngle: 2 * Math.PI }) ?? '',
        index: i,
        name: String(row[nameKey]),
        value: values[i],
      };
    });
  });
}

